<template>
  <html>
    <body>
      <h1 align="center">隆庆气体工具箱</h1>
      <div>
        <!-- <AttributeBind />
        <TwoWayBinding />
        <ConditionalRendering />
        <ListRendering />
        <TodoItem /> -->
      </div>
      <div id="todo-list-example" class="demo">
        <!-- <Counter id="timer"/> -->
        <form v-on:submit.prevent="addNewTodo">
          <label for="new-todo">有效投标价:</label>
          <input
            class="input"
            type="number"
            v-model="newTodoText"
            id="new-todo"
            placeholder="input"
            required
          />

          <a class="clear" @click="clear1()"></a>
          <button>+</button>
        </form>
          <ul   >

          <li v-for="(todo) in todos" :key="todo.id"> 
            {{todo.id + 1}}:{{todo.title}} -> {{cal(total,todo.title)}}
           <button v-on:click="remove">-</button>
       </li>
        </ul>
        <ol>
          评标基准价:
          {{
            total
          }}
        </ol>
      </div>
    </body>
  </html>
</template>

<script>
import { ref } from "vue";

import AddList from "./components/AddList.vue";

export default {
  name: "App",
  components: {
    AddList,
  },
  data() {
    return {  
      total: 1,
      newTodoText: "",
      todos: [],
      nextTodoId: 0,
      
    };
  },
  methods: {
    addNewTodo() {
      this.todos.push({
        id: this.nextTodoId++,
        title: this.newTodoText,
        
      });
      var list = [];
      var len = this.nextTodoId;
      console.log("this len: " + len)
      for (var i = 0; i < len; i++) {
        list[i] = Number(this.newTodoText);
      }
      list = list.sort((a, b) => Number(a) - Number(b));
      len = list.length;
      if (len > 8) {
        console.log(" 8 list.length:" + list.length)
        list[len - 1] = 0;
        list[len - 2] = 0;
        list[0] = 0;
        len = len - 2;
      }
      if ((list.length > 4) & (list.length < 9)) {
        console.log(" 4 list.length:" + list.length)
        list[list.length - 1] = 0;
        list[0] = 0;
        len = len - 1;
      }
      this.total = list.reduce(
        (partialSum, a) => Number(partialSum) + Number(a),
        0
      );
      this.total = ((this.total * 95) / (100 * len)).toFixed(2)
     
      
    },
   
    remove(index, num) {
      this.nextTodoId--;
      var list = [];
      var len = this.nextTodoId;
      console.log("this len: " + len)
      for (var i = 0; i < len; i++) {
        list[i] = Number(this.newTodoText);
      }
      list = list.sort((a, b) => Number(a) - Number(b));
      len = list.length;
      if (len > 8) {
        console.log(" 8 list.length:" + list.length)
        list[len - 1] = 0;
        list[len - 2] = 0;
        list[0] = 0;
        len = len - 2;
      }
      if ((list.length > 4) & (list.length < 9)) {
        console.log(" 4 list.length:" + list.length)
        list[list.length - 1] = 0;
        list[0] = 0;
        len = len - 1;
      }
      this.total = list.reduce(
        (partialSum, a) => Number(partialSum) + Number(a),
        0
      );
      this.total = ((this.total * 95) / (100 * len)).toFixed(2);
      this.todos.splice(index, num);
      console.log(this.nextTodoId);
    },
    cal(A,a){
      console.log("a"+a + "A:" +A )
      return (a>A) ? (110 - a*60/A) : (70 - a*20/A).toFixed(2)
    },
    clear1() {
      if (this.newTodoText) {
        this.newTodoText = "";
      }
    },
  },
  setup() {
    return {
      score: ref(1234),
    };
  },
};
</script>
